const data = $json.body || $json;

const metadata = data.metadata || {};
const trivy = data.trivy || {};
const semgrep = data.semgrep || {};
const zap = data.zap || {};

let findings = [];

function cleanHtml(text = "") {
  return String(text).replace(/<[^>]*>/g, "").trim();
}

function normalizeSeverity(tool, rawSeverity = "") {
  const toolName = String(tool || "").toLowerCase();
  const s = String(rawSeverity || "").toLowerCase();

  // Semgrep severity:
  // ERROR   -> high
  // WARNING -> medium
  // INFO    -> info
  if (toolName === "semgrep") {
    if (s === "error") return "high";
    if (s === "warning") return "medium";
    if (s === "info") return "info";
  }

  // Trivy / ZAP / generic
  if (s.includes("critical")) return "critical";
  if (s.includes("high")) return "high";
  if (s.includes("medium")) return "medium";
  if (s.includes("moderate")) return "medium";
  if (s.includes("low")) return "low";
  if (s.includes("informational")) return "info";
  if (s.includes("info")) return "info";

  return "info";
}

// Trivy
for (const result of trivy.Results || []) {
  for (const vuln of result.Vulnerabilities || []) {
    const rawSeverity = vuln.Severity || "UNKNOWN";

    findings.push({
      tool: "trivy",
      type: "container/dependency",
      severity: normalizeSeverity("trivy", rawSeverity),
      raw_severity: rawSeverity,

      cve: vuln.VulnerabilityID || "",
      package: vuln.PkgName || "",
      installed_version: vuln.InstalledVersion || "",
      fixed_version: vuln.FixedVersion || "",
      title: vuln.Title || vuln.VulnerabilityID || "",
      file: result.Target || "",
      line: null,

      cvss:
        vuln.CVSS?.nvd?.V3Score ||
        vuln.CVSS?.redhat?.V3Score ||
        vuln.CVSS?.ghsa?.V3Score ||
        0,

      description: cleanHtml(vuln.Description || ""),
      solution: vuln.FixedVersion
        ? `Upgrade ${vuln.PkgName} to ${vuln.FixedVersion}`
        : ""
    });
  }
}

// Semgrep
for (const r of semgrep.results || []) {
  const rawSeverity = r.extra?.severity || "UNKNOWN";

  findings.push({
    tool: "semgrep",
    type: "sast",
    severity: normalizeSeverity("semgrep", rawSeverity),
    raw_severity: rawSeverity,

    rule_id: r.check_id || "",
    title: r.extra?.message || r.check_id || "Semgrep finding",
    file: r.path || "",
    line: r.start?.line || null,

    message: r.extra?.message || "",
    code: r.extra?.lines || "",
    cvss: 0,

    description: cleanHtml(
      r.extra?.metadata?.description ||
      r.extra?.message ||
      ""
    ),

    solution: cleanHtml(
      r.extra?.metadata?.fix ||
      r.extra?.metadata?.remediation ||
      ""
    )
  });
}

// ZAP
for (const site of zap.site || []) {
  for (const alert of site.alerts || []) {
    const rawSeverity = alert.riskdesc || alert.risk || "UNKNOWN";

    findings.push({
      tool: "zap",
      type: "dast",
      severity: normalizeSeverity("zap", rawSeverity),
      raw_severity: rawSeverity,

      title: alert.alert || "ZAP alert",
      url: alert.url || site["@name"] || "",
      file: alert.url || site["@name"] || "",
      line: null,

      confidence: alert.confidence || "",
      description: cleanHtml(alert.desc || ""),
      solution: cleanHtml(alert.solution || ""),
      cvss: 0
    });
  }
}

return [
  {
    json: {
      metadata,
      total_findings: findings.length,
      findings
    }
  }
];

const findings = $json.findings || [];

let counts = {
  critical: 0,
  high: 0,
  medium: 0,
  low: 0,
  info: 0
};

let tool_counts = {
  semgrep: 0,
  trivy: 0,
  zap: 0
};

for (const f of findings) {
  const sev = String(f.severity || "info").toLowerCase();
  const tool = String(f.tool || "").toLowerCase();

  if (counts[sev] !== undefined) {
    counts[sev]++;
  } else {
    counts.info++;
  }

  if (tool_counts[tool] !== undefined) {
    tool_counts[tool]++;
  }
}

const baseScore =
  counts.critical * 10 +
  counts.high * 7 +
  counts.medium * 3 +
  counts.low * 1;

const normalizedScore = Math.min(10, Math.round(baseScore / 5));

let block_reasons = [];

if (counts.critical > 0) {
  block_reasons.push("Critical vulnerability found");
}

if (counts.high > 0) {
  block_reasons.push("High severity vulnerability found");
}

// Nhiều medium cũng nên block vì có thể là rủi ro tích lũy
if (counts.medium >= 10) {
  block_reasons.push("Too many medium severity findings");
}

if (normalizedScore >= 8) {
  block_reasons.push("Risk score threshold exceeded");
}

const shouldBlock = block_reasons.length > 0;

return [
  {
    json: {
      ...$json,
      severity_counts: counts,
      tool_counts,
      pre_risk_score: normalizedScore,
      should_block_precheck: shouldBlock,
      block_reasons
    }
  }
];

const findings = $json.findings || [];
const counts = $json.severity_counts || {};
const reasons = $json.block_reasons || [];

const decision = $json.should_block_precheck === true ? "BLOCK" : "ALLOW";

const severity =
  (counts.critical || 0) > 0 ? "critical" :
  (counts.high || 0) > 0 ? "high" :
  (counts.medium || 0) > 0 ? "medium" :
  (counts.low || 0) > 0 ? "low" :
  "info";

return [
  {
    json: {
      project_name: $json.metadata?.repo || "unknown-project",
      repo: $json.metadata?.repo || "",
      branch: $json.metadata?.branch || "",
      commit: $json.metadata?.commit || "",

      total_findings: $json.total_findings || findings.length,
      risk_score: $json.pre_risk_score || 0,
      severity,

      analysis_type: "rule_based_security_gate",
      gate_reasons: reasons,

      ai_summary: "",
      ai_fix_suggestion: "",

      should_block_pipeline: decision === "BLOCK",
      pipeline_decision: decision,

      severity_counts: counts,
      tool_counts: $json.tool_counts || {},

      ai_findings: [],
      normal_findings: findings,
      all_findings: findings
    }
  }
];

const gate = $("Format Report for Dashboard").first().json;
const dbResponse = $json || {};

return [
  {
    json: {
      pipeline_decision: gate.pipeline_decision,
      should_block_pipeline: gate.should_block_pipeline,
      risk_score: gate.risk_score,
      severity: gate.severity,
      severity_counts: gate.severity_counts,
      total_findings: gate.total_findings,
      message:
        gate.pipeline_decision === "BLOCK"
          ? "Security gate blocked the pipeline. CD deployment stopped."
          : "Security gate passed. CD deployment allowed.",
      dashboard_saved: true,
      scan_id: dbResponse.id || dbResponse.scan_id || null
    }
  }
];
